#include <string.h>


#define lexbor_mraw_meta_size()                                                \
    (((sizeof(size_t) % LEXBOR_MEM_ALIGN_STEP) != 0)                           \
    ? sizeof(size_t)                                                           \
        + (LEXBOR_MEM_ALIGN_STEP - (sizeof(size_t) % LEXBOR_MEM_ALIGN_STEP))   \
    : sizeof(size_t))


